# geometry.spy: Concrete shape implementations and Point struct
from shapes import Shape, IArea, IPerimeter, ShapeType, Color

# Point struct for coordinates
struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        # Simplified distance (squared, then sqrt via ** 0.5)
        return (dx * dx + dy * dy) ** 0.5

# Circle class
class Circle(Shape, IArea, IPerimeter):
    radius: float
    center: Point

    def __init__(self, name: str, color: Color, radius: float, center: Point):
        self.name = name
        self.color = color
        self._shape_type = ShapeType.GEOMETRIC
        self.radius = radius
        self.center = center

    @virtual
    def get_area(self) -> float:
        pi: float = 3.14159
        return pi * self.radius * self.radius

    @virtual
    def get_perimeter(self) -> float:
        pi: float = 3.14159
        return 2.0 * pi * self.radius

    @virtual
    def get_description(self) -> str:
        return "Circle: " + self.name

    @virtual
    def get_color_name(self) -> str:
        return self.color.name

# Rectangle class
class Rectangle(Shape, IArea, IPerimeter):
    width: float
    height: float
    corner: Point

    def __init__(self, name: str, color: Color, width: float, height: float, corner: Point):
        self.name = name
        self.color = color
        self._shape_type = ShapeType.GEOMETRIC
        self.width = width
        self.height = height
        self.corner = corner

    @virtual
    def get_area(self) -> float:
        return self.width * self.height

    @virtual
    def get_perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @virtual
    def get_description(self) -> str:
        return "Rectangle: " + self.name

    @virtual
    def get_color_name(self) -> str:
        return self.color.name

# Triangle class
class Triangle(Shape, IArea, IPerimeter):
    side_a: float
    side_b: float
    side_c: float
    vertex: Point

    def __init__(self, name: str, color: Color, a: float, b: float, c: float, vertex: Point):
        self.name = name
        self.color = color
        self._shape_type = ShapeType.GEOMETRIC
        self.side_a = a
        self.side_b = b
        self.side_c = c
        self.vertex = vertex

    @virtual
    def get_area(self) -> float:
        # Heron's formula
        s: float = (self.side_a + self.side_b + self.side_c) / 2.0
        area_sq: float = s * (s - self.side_a) * (s - self.side_b) * (s - self.side_c)
        return area_sq ** 0.5

    @virtual
    def get_perimeter(self) -> float:
        return self.side_a + self.side_b + self.side_c

    @virtual
    def get_description(self) -> str:
        return "Triangle: " + self.name

    @virtual
    def get_color_name(self) -> str:
        return self.color.name
